// networkModule.js - React Native Networking Module for API and IoT Devices

const API_BASE_URL = 'https://api.example.com';
const DEFAULT_TIMEOUT = 10000; // 10 seconds
const IOT_TIMEOUT = 5000; // 5 seconds for local devices

// Token storage (in production, use secure storage like react-native-keychain)
let authToken = null;

// ============================================
// Utility Functions
// ============================================

const setAuthToken = (token) => {
  authToken = token;
};

const clearAuthToken = () => {
  authToken = null;
};

const getAuthToken = () => authToken;

/**
 * Creates an AbortController with timeout
 */
const createTimeoutController = (timeoutMs) => {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), timeoutMs);
  return { controller, timeoutId };
};

/**
 * Builds headers for API requests
 */
const buildApiHeaders = (customHeaders = {}) => {
  const headers = {
    'Content-Type': 'application/json',
    'Accept': 'application/json',
    'X-Client-Platform': 'react-native',
    'X-Client-Version': '1.0.0',
    ...customHeaders,
  };

  if (authToken) {
    headers['Authorization'] = `Bearer ${authToken}`;
  }

  return headers;
};

/**
 * Builds headers for IoT device requests
 */
const buildIoTHeaders = (customHeaders = {}) => {
  return {
    'Content-Type': 'application/json',
    'Accept': 'application/json',
    'X-IoT-Client': 'react-native-controller',
    ...customHeaders,
  };
};

/**
 * Validates if an IP is in the local network range (192.168.x.x)
 */
const isLocalIoTAddress = (url) => {
  try {
    const regex = /^https?:\/\/192\.168\.\d{1,3}\.\d{1,3}/;
    return regex.test(url);
  } catch {
    return false;
  }
};

/**
 * Parses response based on content type
 */
const parseResponse = async (response) => {
  const contentType = response.headers.get('content-type') || '';

  if (contentType.includes('application/json')) {
    return response.json();
  } else if (contentType.includes('text/')) {
    return response.text();
  } else if (contentType.includes('application/octet-stream')) {
    return response.blob();
  }

  // Default to trying JSON, fallback to text
  try {
    return await response.json();
  } catch {
    return response.text();
  }
};

// ============================================
// Error Classes
// ============================================

class NetworkError extends Error {
  constructor(message, statusCode = null, responseBody = null, url = '') {
    super(message);
    this.name = 'NetworkError';
    this.statusCode = statusCode;
    this.responseBody = responseBody;
    this.url = url;
    this.timestamp = new Date().toISOString();
  }
}

class TimeoutError extends NetworkError {
  constructor(url, timeoutMs) {
    super(`Request to ${url} timed out after ${timeoutMs}ms`);
    this.name = 'TimeoutError';
    this.url = url;
    this.timeoutMs = timeoutMs;
  }
}

class IoTDeviceError extends NetworkError {
  constructor(message, deviceIp, statusCode = null) {
    super(message, statusCode);
    this.name = 'IoTDeviceError';
    this.deviceIp = deviceIp;
  }
}

// ============================================
// Request Interceptors / Middleware
// ============================================

const requestInterceptors = [];
const responseInterceptors = [];

const addRequestInterceptor = (interceptor) => {
  requestInterceptors.push(interceptor);
  return requestInterceptors.length - 1;
};

const addResponseInterceptor = (interceptor) => {
  responseInterceptors.push(interceptor);
  return responseInterceptors.length - 1;
};

const removeRequestInterceptor = (index) => {
  requestInterceptors[index] = null;
};

const removeResponseInterceptor = (index) => {
  responseInterceptors[index] = null;
};

const applyRequestInterceptors = async (config) => {
  let modifiedConfig = { ...config };
  for (const interceptor of requestInterceptors) {
    if (interceptor) {
      modifiedConfig = await interceptor(modifiedConfig);
    }
  }
  return modifiedConfig;
};

const applyResponseInterceptors = async (response, config) => {
  let modifiedResponse = response;
  for (const interceptor of responseInterceptors) {
    if (interceptor) {
      modifiedResponse = await interceptor(modifiedResponse, config);
    }
  }
  return modifiedResponse;
};

// ============================================
// Retry Logic
// ============================================

const wait = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

const retryRequest = async (requestFn, options = {}) => {
  const {
    maxRetries = 3,
    baseDelay = 1000,
    maxDelay = 10000,
    backoffMultiplier = 2,
    retryOnStatusCodes = [408, 429, 500, 502, 503, 504],
  } = options;

  let lastError;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      return await requestFn();
    } catch (error) {
      lastError = error;

      if (attempt === maxRetries) break;

      // Don't retry on client errors (4xx) except specific ones
      if (
        error.statusCode &&
        error.statusCode >= 400 &&
        error.statusCode < 500 &&
        !retryOnStatusCodes.includes(error.statusCode)
      ) {
        throw error;
      }

      const delay = Math.min(
        baseDelay * Math.pow(backoffMultiplier, attempt),
        maxDelay
      );
      const jitter = delay * (0.5 + Math.random() * 0.5);

      console.log(
        `[NetworkModule] Retry attempt ${attempt + 1}/${maxRetries} after ${Math.round(jitter)}ms`
      );
      await wait(jitter);
    }
  }

  throw lastError;
};

// ============================================
// Core Request Function
// ============================================

const makeRequest = async (url, options = {}) => {
  const {
    method = 'GET',
    headers = {},
    body = null,
    timeout = DEFAULT_TIMEOUT,
    retry = false,
    retryOptions = {},
    isIoT = false,
  } = options;

  const requestFn = async () => {
    const { controller, timeoutId } = createTimeoutController(timeout);

    // Build config
    let config = {
      method: method.toUpperCase(),
      headers: isIoT ? buildIoTHeaders(headers) : buildApiHeaders(headers),
      signal: controller.signal,
    };

    if (body && !['GET', 'HEAD'].includes(config.method)) {
      config.body =
        typeof body === 'string' ? body : JSON.stringify(body);
    }

    // Apply request interceptors
    config = await applyRequestInterceptors(config);

    console.log(`[NetworkModule] ${config.method} ${url}`);

    try {
      let response = await fetch(url, config);
      clearTimeout(timeoutId);

      // Apply response interceptors
      response = await applyResponseInterceptors(response, config);

      if (!response.ok) {
        let errorBody = null;
        try {
          errorBody = await parseResponse(response);
        } catch {
          // ignore parse error
        }

        if (isIoT) {
          throw new IoTDeviceError(
            `IoT device returned status ${response.status}: ${response.statusText}`,
            url,
            response.status
          );
        }

        throw new NetworkError(
          `HTTP ${response.status}: ${response.statusText}`,
          response.status,
          errorBody,
          url
        );
      }

      const data = await parseResponse(response);

      return {
        data,
        status: response.status,
        statusText: response.statusText,
        headers: response.headers,
        ok: response.ok,
      };
    } catch (error) {
      clearTimeout(timeoutId);

      if (error.name === 'AbortError') {
        throw new TimeoutError(url, timeout);
      }

      if (error instanceof NetworkError) {
        throw error;
      }

      throw new NetworkError(
        `Network request failed: ${error.message}`,
        null,
        null,
        url
      );
    }
  };

  if (retry) {
    return retryRequest(requestFn, retryOptions);
  }

  return requestFn();
};

// ============================================
// API Client (HTTPS - api.example.com)
