// ============================================
// IoT Device Client (HTTP/HTTPS - Local Network)
// ============================================

const IoTClient = {
  /**
   * Constructs the base URL for an IoT device
   * Supports both HTTP (legacy) and HTTPS
   */
  _getBaseUrl: (deviceIp, useHttps = false) => {
    if (!isLocalIoTAddress(`http://${deviceIp}`)) {
      console.warn(
        `[IoTClient] Warning: ${deviceIp} does not appear to be a local network address`
      );
    }
    const protocol = useHttps ? 'https' : 'http';
    return `${protocol}://${deviceIp}`;
  },

  /**
   * Generic request to IoT device
   */
  request: (deviceIp, endpoint, options = {}) => {
    const { useHttps = false, port = null, ...restOptions } = options;
    const baseUrl = IoTClient._getBaseUrl(deviceIp, useHttps);
    const portSuffix = port ? `:${port}` : '';
    const url = `${baseUrl}${portSuffix}${endpoint}`;

    return makeRequest(url, {
      timeout: IOT_TIMEOUT,
      isIoT: true,
      ...restOptions,
    });
  },

  /**
   * GET request to IoT device
   */
  get: (deviceIp, endpoint, options = {}) => {
    return IoTClient.request(deviceIp, endpoint, {
      method: 'GET',
      ...options,
    });
  },

  /**
   * POST request to IoT device
   */
  post: (deviceIp, endpoint, body, options = {}) => {
    return IoTClient.request(deviceIp, endpoint, {
      method: 'POST',
      body,
      ...options,
    });
  },

  /**
   * PUT request to IoT device
   */
  put: (deviceIp, endpoint, body, options = {}) => {
    return IoTClient.request(deviceIp, endpoint, {
      method: 'PUT',
      body,
      ...options,
    });
  },

  // ============================================
  // Common IoT Device Operations
  // ============================================

  /**
   * Discover device info
   */
  discover: (deviceIp, options = {}) => {
    return IoTClient.get(deviceIp, '/info', {
      timeout: 3000,
      ...options,
    });
  },

  /**
   * Ping device to check connectivity
   */
  ping: async (deviceIp, options = {}) => {
    try {
      const startTime = Date.now();
      await IoTClient.get(deviceIp, '/ping', {
        timeout: 2000,
        ...options,
      });
      const latency = Date.now() - startTime;
      return { reachable: true, latency, ip: deviceIp };
    } catch {
      return { reachable: false, latency: null, ip: deviceIp };
    }
  },

  /**
   * Get device status
   */
  getStatus: (deviceIp, options = {}) => {
    return IoTClient.get(deviceIp, '/status', options);
  },

  /**
   * Send command to device
   */
  sendCommand: (deviceIp, command, params = {}, options = {}) => {
    return IoTClient.post(
      deviceIp,
      '/command',
      { command, params, timestamp: Date.now() },
      options
    );
  },

  /**
   * Get device configuration
   */
  getConfig: (deviceIp, options = {}) => {
    return IoTClient.get(deviceIp, '/config', options);
  },

  /**
   * Update device configuration
   */
  setConfig: (deviceIp, config, options = {}) => {
    return IoTClient.put(deviceIp, '/config', config, options);
  },

  /**
   * Get sensor data from device
   */
  getSensorData: (deviceIp, sensorId = null, options = {}) => {
    const endpoint = sensorId ? `/sensors/${sensorId}` : '/sensors';
    return IoTClient.get(deviceIp, endpoint, options);
  },

  /**
   * Toggle device on/off
   */
  toggle: (deviceIp, state, options = {}) => {
    return IoTClient.post(
      deviceIp,
      '/toggle',
      { state: state ? 'on' : 'off', timestamp: Date.now() },
      options
    );
  },

  /**
   * Reboot device
   */
  reboot: (deviceIp, options = {}) => {
    return IoTClient.post(deviceIp, '/reboot', { timestamp: Date.now() }, {
      timeout: 3000,
      ...options,
    });
  },

  /**
   * Update device firmware via local network
   */
  updateFirmware: (deviceIp, firmwareUrl, options = {}) => {
    return IoTClient.post(
      deviceIp,
      '/firmware/update',
      { firmware_url: firmwareUrl, timestamp: Date.now() },
      { timeout: 60000, ...options }
    );
  },

  /**
   * Scan a range of local IPs for IoT devices
   */
  scanNetwork: async (subnet = '192.168.1', startIp = 1, endIp = 254, options = {}) => {
    const { concurrency = 20 } = options;
    const devices = [];
    const ips = [];

    for (let i = startIp; i <= endIp; i++) {
      ips.push(`${subnet}.${i}`);
    }

    // Process in batches for concurrency control
    for (let i = 0; i < ips.length; i += concurrency) {
      const batch = ips.slice(i, i + concurrency);
      const results = await Promise.allSettled(
        batch.map((ip) => IoTClient.ping(ip, options))
      );

      results.forEach((result) => {
        if (result.status === 'fulfilled' && result.value.reachable) {
          devices.push(result.value);
        }
      });
    }

    return devices;
  },

  /**
   * Discover detailed info for multiple devices
   */
  discoverMultiple: async (deviceIps, options = {}) => {
    const results = await Promise.allSettled(
      deviceIps.map(async (ip) => {
        const pingResult = await IoTClient.ping(ip, options);
        if (!pingResult.reachable) {
          return { ip, reachable: false, info: null };
        }

        try {
          const infoResult = await IoTClient.discover(ip, options);
          return { ip, reachable: true, info: infoResult.data, latency: pingResult.latency };
        } catch {
          return { ip, reachable: true, info: null, latency: pingResult.latency };
        }
      })
    );

    return results
      .filter((r) => r.status === 'fulfilled')
      .map((r) => r.value);
  },
};

// ============================================
// Connection Health Monitor
// ============================================

class ConnectionMonitor {
  constructor() {
    this.listeners = [];
    this.apiHealthy = null;
    this.deviceHealth = new Map();
    this.intervalId = null;
  }

  addListener(callback) {
    this.listeners.push(callback);
    return () => {
      this.listeners = this.listeners.filter((l) => l !== callback);
    };
  }

  _notify(event) {
    this.listeners.forEach((listener) => {
      try {
        listener(event);
      } catch (err) {
        console.error('[ConnectionMonitor] Listener error:', err);
      }
    });
  }

  async checkApiHealth() {
    try {
      await makeRequest(`${API_BASE_URL}/health`, {
        method: 'GET',
        timeout: 5000,
      });
      const wasUnhealthy = this.apiHealthy === false;
      this.apiHealthy = true;
      if (wasUnhealthy) {
        this._notify({ type: 'api_recovered', timestamp: Date.now() });
      }
      return true;
    } catch {
      const wasHealthy = this.apiHealthy !== false;
      this.apiHealthy = false;
      if (wasHealthy) {
        this._notify({ type: 'api_down', timestamp: Date.now() });
      }
      return false;
    }
  }

  async checkDeviceHealth(deviceIp) {
    const result = await IoTClient.ping(deviceIp);
    const previousState = this.deviceHealth.get(deviceIp);
    this.deviceHealth.set(deviceIp, result.reachable);

    if (previousState !== undefined && previousState !== result.reachable) {
      this._notify({
        type: result.reachable ? 'device_recovered' : 'device_down',
        deviceIp,
        timestamp: Date.now(),
      });
    }

    return result;
  }

  startMonitoring(deviceIps = [], intervalMs = 30000) {
    this.stopMonitoring();

    const check = async () => {
      await this.checkApiHealth();
      await Promise.allSettled(
        deviceIps.map((ip) => this.checkDeviceHealth(ip))
      );
    };

    check(); // Initial check
    this.intervalId = setInterval(check, intervalMs);
  }

  stopMonitoring() {
    if (this.intervalId) {
      clearInterval(this.intervalId);
      this.intervalId = null;
    }
  }

  getStatus() {
    return {
      api: this.apiHealthy,
      devices: Object.fromEntries(this.deviceHealth),
    };
  }
}

// ============================================
// Request Queue for Offline Support
// ============================================

class RequestQueue {
  constructor() {
    this.queue = [];
    this.processing = false;
  }

  enqueue(requestConfig) {
    const id = `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
    this.queue.push({ id, config: requestConfig, createdAt: Date.now() });
    console.log(`[RequestQueue] Enqueued request ${id}, queue size: ${this.queue.length}`);
    return id;
  }

  async processQueue() {
    if (this.processing || this.queue.length === 0) return;
    this.processing = true;

    console.log(`[RequestQueue] Processing ${this.queue.length} queued requests`);

    const failedItems = [];

    while (this.queue.length > 0) {
      const item = this.queue.shift();

      try {
        const { url, ...options } = item.config;
        await makeRequest(url, options);
        console.log(`[RequestQueue] Successfully processed request ${item.id}`);
      } catch (error) {
        console.warn(`[RequestQueue] Failed to process request ${item.id}:`, error.message);

        // Re-queue if it's a network error (not a client error)
        if (!error.statusCode || error.statusCode >= 500) {
          failedItems.push(item);
        }
      }
    }

    // Re-add failed items
    this.queue = [...failedItems, ...this.queue];
    this.processing = false;

    if (failedItems.length > 0) {
      console.log(`[RequestQueue] ${failedItems.length} requests re-queued for retry`);
    }
  }

  getQueueSize() {
    return this.queue.length;
  }

  clearQueue() {
    const size = this.queue.length;
    this.queue = [];
    return size;
  }
}

