addResponseInterceptor(async (response, config) => {
  // If we get a 401, try to handle token refresh
  if (response.status === 401 && !config._isRetryAfterRefresh) {
    console.log('[NetworkModule] Received 401, token may be expired');
    // The consuming app should handle token refresh logic
    // This is a hook point for that
  }
  return response;
});

